```python
def lock_path() -> Path:
    return Path.home() / ".memorytree" / "heartbeat.lock"

def acquire_lock() -> bool:
    path = lock_path()
    path.parent.mkdir(parents=True, exist_ok=True)
    if path.exists():
        try:
            stored_pid = int(path.read_text(encoding="utf-8").strip())
        except (OSError, ValueError):
            log.warning("Corrupt lock file detected, removing: %s", path)
            _remove_lock(path)
        else:
            if _is_process_alive(stored_pid):
                return False
            log.warning("Stale lock detected (PID %d is dead), reclaiming.", stored_pid)
            _remove_lock(path)
    try:
        fd = os.open(str(path), os.O_CREAT | os.O_EXCL | os.O_WRONLY)
        os.write(fd, str(os.getpid()).encode("utf-8"))
        os.close(fd)
    except FileExistsError:
        return False
    except OSError:
        return False
    return True

def release_lock() -> None:
    _remove_lock(lock_path())

def read_lock_pid() -> int | None:
    path = lock_path()
    if not path.exists():
        return None
    try:
        return int(path.read_text(encoding="utf-8").strip())
    except (OSError, ValueError):
        return None

def _is_process_alive(pid: int) -> bool:
    if pid <= 0:
        return False
    if sys.platform == "win32":
        return _is_process_alive_windows(pid)
    return _is_process_alive_unix(pid)

def _is_process_alive_unix(pid: int) -> bool:
    try:
        os.kill(pid, 0)
        return True
    except ProcessLookupError:
        return False
    except PermissionError:
        return True

def _is_process_alive_windows(pid: int) -> bool:
    try:
        import ctypes
        kernel32 = ctypes.windll.kernel32
        PROCESS_QUERY_LIMITED_INFORMATION = 0x1000
        handle = kernel32.OpenProcess(PROCESS_QUERY_LIMITED_INFORMATION, False, pid)
        if handle:
            kernel32.CloseHandle(handle)
            return True
        return False
    except Exception:
        return False

def _remove_lock(path: Path) -> None:
    try:
        path.unlink(missing_ok=True)
    except OSError:
        pass
```

TypeScript implementation notes:
- `lockPath()` → `resolve(homedir(), '.memorytree', 'heartbeat.lock')`
